"""
Generates 400 sentence-order questions: A1:200  A2:150  B1:50
Each entry has: id, level, topic, words (scrambled), answer (tokens), correct (display), tip (English), structure (English pattern)
"""
import json, random
random.seed(99)

def sid(n): return f"SO{n:04d}"

def scramble(tokens):
    t = tokens[:]
    for _ in range(20):
        random.shuffle(t)
        if t != tokens:
            return t
    return t[::-1] if t == tokens else t

