("A1","Verben",["Sie","geht","jeden","Morgen","joggen","."],"Sie geht jeden Morgen joggen.","'jeden Morgen' (every morning) follows verb; activity infinitive at end.","Subject + Verb + Time + Infinitive"),
("A1","Verben",["Ich","brauche","ein","neues","Wörterbuch","."],"Ich brauche ein neues Wörterbuch.","Neuter indefinite article + adjective '-es' (strong ending) + noun.","Subject + Verb + ein + Adj(-es) + Neuter noun"),
("A1","Verben",["Du","schreibst","eine","E-Mail","an","deine","Freundin","."],"Du schreibst eine E-Mail an deine Freundin.","Direct object first, then 'an + accusative' shows the recipient.","Subject + Verb + Object + an + Possessive + Noun"),
("A1","Verben",["Das","Kind","schläft","um","acht","Uhr","."],"Das Kind schläft um acht Uhr.","'um + time' gives the exact clock time.","Subject + Verb + um + Time"),
("A1","Verben",["Wir","besuchen","morgen","unsere","Großeltern","."],"Wir besuchen morgen unsere Großeltern.","Time adverb 'morgen' follows the verb, before the object.","Subject + Verb + Time + Possessive + Object"),
("A1","Verben",["Er","fährt","mit","dem","Fahrrad","zur","Schule","."],"Er fährt mit dem Fahrrad zur Schule.","Means of transport (mit + dative) before destination (zur = zu der).","Subject + Verb + mit + dem + Noun + zur + Noun"),
("A1","Verben",["Ich","höre","gern","Musik","."],"Ich höre gern Musik.","'gern' shows preference; mass noun 'Musik' has no article.","Subject + Verb + gern + Object (no article)"),
("A1","Verben",["Sie","tanzt","sehr","gut","."],"Sie tanzt sehr gut.","'sehr gut' as an adverb phrase modifying the verb.","Subject + Verb + sehr + Adverb"),
("A1","Verben",["Du","isst","zu","viel","Süßes","."],"Du isst zu viel Süßes.","'zu viel' (too much) + nominalised adjective 'Süßes'.","Subject + Verb + zu viel + Noun"),
("A1","Verben",["Wir","wohnen","in","einer","kleinen","Wohnung","."],"Wir wohnen in einer kleinen Wohnung.","'in + dative' for location; feminine: 'einer', adjective '-en'.","Subject + Verb + in + einer + Adj(-en) + Noun"),
("A1","Verben",["Er","schreibt","jeden","Tag","in","sein","Tagebuch","."],"Er schreibt jeden Tag in sein Tagebuch.","Time before location; 'in + accusative' shows direction into the diary.","Subject + Verb + Time + in + Possessive + Noun"),
("A1","Verben",["Sie","lernt","für","die","Prüfung","."],"Sie lernt für die Prüfung.","'für + accusative' gives the purpose.","Subject + Verb + für + die + Noun"),
("A1","Verben",["Ich","kaufe","einen","Apfel","und","eine","Banane","."],"Ich kaufe einen Apfel und eine Banane.","Two accusative objects: 'einen' (masc.) and 'eine' (fem.).","Subject + Verb + einen + Noun + und + eine + Noun"),
("A1","Verben",["Er","wacht","um","sieben","Uhr","auf","."],"Er wacht um sieben Uhr auf.","Separable verb 'aufwachen': prefix 'auf' moves to the end.","Subject + Verb stem + Time + Prefix (end)"),
("A1","Verben",["Sie","singen","ein","Lied","."],"Sie singen ein Lied.","Neuter accusative: 'ein Lied'.","Subject + Verb + ein (neut.) + Noun"),

# ── Zeitangaben (141–160) ─────────────────
("A1","Zeit",["Der","Unterricht","beginnt","um","neun","Uhr","."],"Der Unterricht beginnt um neun Uhr.","'um + clock time' gives the exact start time.","Subject + Verb + um + Time"),
("A1","Zeit",["Heute","Abend","gehe","ich","ins","Theater","."],"Heute Abend gehe ich ins Theater.","Time phrase first → verb flips to position 2 (verb-second rule).","Time + Verb + Subject + ins + Noun"),
("A1","Zeit",["Morgen","haben","wir","keinen","Unterricht","."],"Morgen haben wir keinen Unterricht.","'Morgen' fronted → verb second; 'keinen' negates the masculine noun.","Time adverb + Verb + Subject + keinen + Noun"),
("A1","Zeit",["Er","kommt","um","halb","drei","."],"Er kommt um halb drei.","'halb drei' = half past two (2:30); 'um' introduces the time.","Subject + Verb + um + halb + Number"),
("A1","Zeit",["Am","Wochenende","schlafe","ich","lange","."],"Am Wochenende schlafe ich lange.","'am Wochenende' fronted → verb at position 2.","Time phrase + Verb + Subject + Adverb"),
("A1","Zeit",["Im","Sommer","fahren","wir","ans","Meer","."],"Im Sommer fahren wir ans Meer.","'Im Sommer' (in summer) fronted; verb flips before subject.","Time phrase + Verb + Subject + Destination"),
("A1","Zeit",["Jeden","Dienstag","habe","ich","Sport","."],"Jeden Dienstag habe ich Sport.","Repeated time ('jeden + weekday') fronted; verb second.","Time phrase + Verb + Subject + Activity"),
("A1","Zeit",["Der","Bus","fährt","alle","zehn","Minuten","."],"Der Bus fährt alle zehn Minuten.","'alle + time unit' expresses a regular interval.","Subject + Verb + alle + Number + Time unit"),
("A1","Zeit",["Das","Geschäft","öffnet","um","neun","Uhr","morgens","."],"Das Geschäft öffnet um neun Uhr morgens.","'morgens' (in the morning) clarifies the time of day.","Subject + Verb + um + Time + morgens"),
("A1","Zeit",["Ich","stehe","immer","früh","auf","."],"Ich stehe immer früh auf.","'immer' (always) follows the verb; 'früh' is an adverb; 'auf' is the separable prefix at the end.","Subject + Verb stem + immer + Adverb + Prefix (end)"),
("A1","Zeit",["Wir","essen","um","zwölf","Uhr","zu","Mittag","."],"Wir essen um zwölf Uhr zu Mittag.","'zu Mittag essen' (to have lunch) is a fixed phrase; time comes first.","Subject + Verb + Time + zu Mittag (set phrase)"),
("A1","Zeit",["Er","geht","abends","spazieren","."],"Er geht abends spazieren.","'abends' (in the evenings) is a time adverb; infinitive at end.","Subject + Verb + Time adverb + Infinitive"),
("A1","Zeit",["Sie","kommt","übermorgen","zurück","."],"Sie kommt übermorgen zurück.","'übermorgen' (the day after tomorrow); separable prefix 'zurück' at end.","Subject + Verb stem + Time + Prefix (end)"),
("A1","Zeit",["Im","Winter","ist","es","sehr","kalt","."],"Im Winter ist es sehr kalt.","Seasonal time phrase fronted; verb second; 'es' as weather subject.","Time phrase + sein + es + sehr + Adjective"),
("A1","Zeit",["Der","Zug","kommt","in","zehn","Minuten","."],"Der Zug kommt in zehn Minuten.","'in + time period' expresses how soon something happens.","Subject + Verb + in + Number + Time unit"),
("A1","Zeit",["Gestern","war","ich","im","Kino","."],"Gestern war ich im Kino.","Past time adverb 'gestern' fronted; 'war' (was) in position 2.","Time adverb + war + Subject + im + Noun"),
("A1","Zeit",["Heute","Nacht","regnet","es","."],"Heute Nacht regnet es.","'heute Nacht' (tonight) fronted; weather 'es' follows.","Time phrase + Verb + es"),
("A1","Zeit",["Die","Apotheke","ist","von","acht","bis","zwanzig","Uhr","geöffnet","."],"Die Apotheke ist von acht bis zwanzig Uhr geöffnet.","'von…bis' (from…to) frames a time range; participle at end.","Subject + sein + von + Time + bis + Time + Participle"),
("A1","Zeit",["Ich","arbeite","von","Montag","bis","Freitag","."],"Ich arbeite von Montag bis Freitag.","'von…bis + weekday' expresses a day range.","Subject + Verb + von + Day + bis + Day"),
("A1","Zeit",["Nächste","Woche","fahre","ich","nach","Berlin","."],"Nächste Woche fahre ich nach Berlin.","'Nächste Woche' fronted; verb second; 'nach + city' for destination.","Time phrase + Verb + Subject + nach + City"),

# ── Familie / Zahlen (161–200) ────────────
("A1","Familie",["Mein","Bruder","heißt","Thomas","."],"Mein Bruder heißt Thomas.","'mein' for masculine nouns in nominative; subject + verb + name.","Possessive + Noun + heißen + Name"),
("A1","Familie",["Meine","Schwester","ist","jünger","als","ich","."],"Meine Schwester ist jünger als ich.","Comparative 'jünger als' (younger than) + pronoun in nominative.","Subject + sein + Comparative + als + Pronoun"),
("A1","Familie",["Unser","Vater","arbeitet","als","Ingenieur","."],"Unser Vater arbeitet als Ingenieur.","'unser' (our) for masculine/neuter nominative; 'als' + profession.","Possessive + Noun + Verb + als + Profession"),
("A1","Familie",["Ihre","Mutter","kommt","aus","Österreich","."],"Ihre Mutter kommt aus Österreich.","'ihre' = her (feminine possessive); 'aus + country' for origin.","Possessive + Noun + Verb + aus + Country"),
("A1","Familie",["Meine","Eltern","wohnen","in","Hamburg","."],"Meine Eltern wohnen in Hamburg.","'meine Eltern' = my parents (plural possessive); location with 'in'.","Possessive + Plural noun + Verb + in + City"),
("A1","Familie",["Sein","Großvater","ist","achtzig","Jahre","alt","."],"Sein Großvater ist achtzig Jahre alt.","'sein' (his) for masculine nouns; age formula.","Possessive + Noun + sein + Number + Jahre alt"),
("A1","Familie",["Wir","haben","drei","Kinder","."],"Wir haben drei Kinder.","Number replaces article; noun stays in accusative plural.","Subject + haben + Number + Plural noun"),
("A1","Familie",["Ihr","Mann","ist","Koch","von","Beruf","."],"Ihr Mann ist Koch von Beruf.","'ihr' = her; 'von Beruf' emphasises the profession.","Possessive + Noun + sein + Profession + von Beruf"),
("A1","Familie",["Meine","Tante","hat","einen","Sohn","und","eine","Tochter","."],"Meine Tante hat einen Sohn und eine Tochter.","Two accusative objects: 'einen' (masc.) and 'eine' (fem.).","Possessive + Noun + haben + einen + Noun + und + eine + Noun"),
("A1","Familie",["Das","ist","mein","Onkel","Peter","."],"Das ist mein Onkel Peter.","Introductory 'Das ist' + possessive + relation + name.","Das + sein + Possessive + Noun + Name"),
("A1","Familie",["Mein","Cousin","studiert","in","Köln","."],"Mein Cousin studiert in Köln.","'in + city' (no article); location after verb.","Possessive + Noun + Verb + in + City"),
("A1","Familie",["Wir","besuchen","unsere","Oma","jedes","Wochenende","."],"Wir besuchen unsere Oma jedes Wochenende.","Accusative object before time phrase.","Subject + Verb + Possessive + Object + Time"),
("A1","Familie",["Meine","Nichte","heißt","Sophie","."],"Meine Nichte heißt Sophie.","'meine' for feminine nouns; 'heißen' + name.","Possessive + Noun + heißen + Name"),
("A1","Familie",["Ihr","Sohn","ist","sehr","klug","."],"Ihr Sohn ist sehr klug.","Possessive 'ihr' (her) + masculine noun; 'sehr' before adjective.","Possessive + Noun + sein + sehr + Adjective"),
("A1","Familie",["Unser","Hund","heißt","Bello","."],"Unser Hund heißt Bello.","'unser' for masculine nominative; verb 'heißen' + name.","Possessive + Noun + heißen + Name"),
("A1","Zahlen",["Ich","bin","dreiundzwanzig","Jahre","alt","."],"Ich bin dreiundzwanzig Jahre alt.","German compound numbers: units before tens (dreiundzwanzig = 23).","Subject + sein + Compound number + Jahre alt"),
("A1","Zahlen",["Das","kostet","fünfzehn","Euro","und","neunzig","Cent","."],"Das kostet fünfzehn Euro und neunzig Cent.","Price: euro amount + und + cent amount.","Subject + Verb + Number + Euro + und + Number + Cent"),
("A1","Zahlen",["Wir","haben","hundert","Wörter","gelernt","."],"Wir haben hundert Wörter gelernt.","Perfekt: haben + object + past participle at the end.","Subject + haben + Number + Object + Participle (end)"),
("A1","Zahlen",["Der","erste","Kurs","beginnt","am","Montag","."],"Der erste Kurs beginnt am Montag.","Ordinal 'erste' (first) as attributive adjective; 'am Montag' = on Monday.","Article + Ordinal + Noun + Verb + am + Day"),
("A1","Zahlen",["Er","hat","drei","Sprachen","gelernt","."],"Er hat drei Sprachen gelernt.","Number + plural noun as object; participle at end.","Subject + haben + Number + Plural noun + Participle"),
("A1","Zahlen",["Das","zweite","Haus","links","ist","unseres","."],"Das zweite Haus links ist unseres.","Ordinal adjective + noun + direction adverb as subject.","Article + Ordinal + Noun + Adverb + sein + Possessive"),
("A1","Zahlen",["Ich","brauche","zwei","Kilo","Äpfel","."],"Ich brauche zwei Kilo Äpfel.","Quantity + unit of measure + noun (no article, no case ending on Kilo).","Subject + Verb + Number + Unit + Noun"),
("A1","Zahlen",["Er","wohnt","im","dritten","Stock","."],"Er wohnt im dritten Stock.","Ordinal in dative: 'dritten' (third); 'im' = in dem.","Subject + Verb + im + Ordinal(-ten) + Noun"),
("A1","Zahlen",["Wir","treffen","uns","am","fünften","Mai","."],"Wir treffen uns am fünften Mai.","Date with ordinal: 'am + ordinal(-ten) + month'.","Subject + Verb + uns + am + Ordinal + Month"),
("A1","Zahlen",["Das","Ticket","kostet","neun","Euro","achtzig","."],"Das Ticket kostet neun Euro achtzig.","Spoken price: euros then cents without a decimal word.","Subject + Verb + Number + Euro + Cents"),

