# ── Trennbare Verben (201–231) ────────────
("A2","Trennbare Verben",["Er","ruft","seine","Mutter","jeden","Sonntag","an","."],"Er ruft seine Mutter jeden Sonntag an.","Separable verbs split: the stem stays at position 2, the prefix moves to the very end.","Subject + Verb stem + Object + Time + Prefix (end)"),
("A2","Trennbare Verben",["Ich","stehe","um","sieben","Uhr","auf","."],"Ich stehe um sieben Uhr auf.","'aufstehen' splits: 'stehe' at position 2, 'auf' at the end.","Subject + Verb stem + Time + Prefix (end)"),
("A2","Trennbare Verben",["Sie","räumt","ihr","Zimmer","auf","."],"Sie räumt ihr Zimmer auf.","'aufräumen': stem 'räumt' stays, prefix 'auf' goes to end.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Wir","kaufen","samstags","im","Supermarkt","ein","."],"Wir kaufen samstags im Supermarkt ein.","'einkaufen': time adverb then location before the prefix 'ein'.","Subject + Verb stem + Time + Location + Prefix (end)"),
("A2","Trennbare Verben",["Er","sieht","jeden","Abend","fern","."],"Er sieht jeden Abend fern.","'fernsehen': stem 'sieht', prefix 'fern' at end.","Subject + Verb stem + Time + Prefix (end)"),
("A2","Trennbare Verben",["Du","fängst","zu","spät","an","."],"Du fängst zu spät an.","'anfangen': 'fängst' at position 2, manner adverb, prefix 'an' at end.","Subject + Verb stem + Manner + Prefix (end)"),
("A2","Trennbare Verben",["Ich","mache","das","Licht","aus","."],"Ich mache das Licht aus.","'ausmachen': object between stem and prefix.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Sie","zieht","nächste","Woche","um","."],"Sie zieht nächste Woche um.","'umziehen' (to move house): time before prefix 'um'.","Subject + Verb stem + Time + Prefix (end)"),
("A2","Trennbare Verben",["Er","schläft","am","Wochenende","aus","."],"Er schläft am Wochenende aus.","'ausschlafen': time phrase before prefix.","Subject + Verb stem + Time + Prefix (end)"),
("A2","Trennbare Verben",["Wir","laden","unsere","Freunde","ein","."],"Wir laden unsere Freunde ein.","'einladen' (to invite): accusative object before prefix 'ein'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Er","bringt","sein","Fahrrad","mit","."],"Er bringt sein Fahrrad mit.","'mitbringen': object between stem and prefix 'mit'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Sie","nimmt","ihren","Regenschirm","mit","."],"Sie nimmt ihren Regenschirm mit.","'mitnehmen': masculine accusative 'ihren' before prefix.","Subject + Verb stem + Object (masc. acc.) + Prefix (end)"),
("A2","Trennbare Verben",["Ich","komme","morgen","früh","zurück","."],"Ich komme morgen früh zurück.","'zurückkommen': two time adverbs ('morgen früh') before prefix.","Subject + Verb stem + Time + Prefix (end)"),
("A2","Trennbare Verben",["Du","siehst","wirklich","gut","aus","."],"Du siehst wirklich gut aus.","'aussehen' (to look/appear): manner adverbs before prefix 'aus'.","Subject + Verb stem + Manner + Prefix (end)"),
("A2","Trennbare Verben",["Wir","machen","um","achtzehn","Uhr","Schluss","."],"Wir machen um achtzehn Uhr Schluss.","'Schluss machen' (to finish): time before the noun object.","Subject + Verb stem + Time + Noun (end)"),
("A2","Trennbare Verben",["Sie","ruft","mich","heute","Abend","zurück","."],"Sie ruft mich heute Abend zurück.","'zurückrufen': accusative pronoun right after stem, time then prefix.","Subject + Verb stem + Pronoun + Time + Prefix (end)"),
("A2","Trennbare Verben",["Ich","fülle","das","Formular","aus","."],"Ich fülle das Formular aus.","'ausfüllen' (to fill in): object between stem and prefix.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Er","stellt","das","Radio","an","."],"Er stellt das Radio an.","'anstellen' (to switch on): object before prefix 'an'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Wir","holen","die","Kinder","von","der","Schule","ab","."],"Wir holen die Kinder von der Schule ab.","'abholen' (to pick up): object + prepositional phrase + prefix.","Subject + Verb stem + Object + von + der + Noun + Prefix (end)"),
("A2","Trennbare Verben",["Du","rufst","bitte","den","Arzt","an","."],"Du rufst bitte den Arzt an.","'anrufen': polite 'bitte' before the accusative object.","Subject + Verb stem + bitte + Object + Prefix (end)"),
("A2","Trennbare Verben",["Er","zieht","die","Jacke","aus","."],"Er zieht die Jacke aus.","'ausziehen' (to take off clothing): object between stem and prefix.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Sie","packt","ihren","Koffer","aus","."],"Sie packt ihren Koffer aus.","'auspacken': accusative object before prefix 'aus'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Ich","schalte","den","Computer","aus","."],"Ich schalte den Computer aus.","'ausschalten' (to switch off): object before prefix.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Wir","bereiten","das","Abendessen","vor","."],"Wir bereiten das Abendessen vor.","'vorbereiten' (to prepare): object between stem and prefix 'vor'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Sie","schreibt","die","Wörter","auf","."],"Sie schreibt die Wörter auf.","'aufschreiben' (to write down): object before prefix 'auf'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Ich","lese","die","Nachrichten","vor","."],"Ich lese die Nachrichten vor.","'vorlesen' (to read aloud): object before prefix 'vor'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Er","macht","das","Fenster","auf","."],"Er macht das Fenster auf.","'aufmachen' (to open): neuter object before prefix 'auf'.","Subject + Verb stem + Object + Prefix (end)"),
("A2","Trennbare Verben",["Er","packt","seinen","Koffer","für","die","Reise","ein","."],"Er packt seinen Koffer für die Reise ein.","'einpacken': object + purpose phrase ('für die Reise') + prefix.","Subject + Verb stem + Object + für + Object + Prefix (end)"),
("A2","Trennbare Verben",["Ich","rufe","dich","morgen","an","."],"Ich rufe dich morgen an.","'anrufen': pronoun object directly after stem, time before prefix.","Subject + Verb stem + Pronoun + Time + Prefix (end)"),
("A2","Trennbare Verben",["Wir","ziehen","nächsten","Monat","in","ein","neues","Haus","um","."],"Wir ziehen nächsten Monat in ein neues Haus um.","'umziehen': time + destination (in + acc.) + prefix at very end.","Subject + Verb stem + Time + in + Object + Prefix (end)"),

# ── Modalverben (231–260) ─────────────────
("A2","Modalverben",["Ich","kann","gut","schwimmen","."],"Ich kann gut schwimmen.","Modal verb at position 2; infinitive goes to the very end.","Subject + Modal + Adverb + Infinitive (end)"),
("A2","Modalverben",["Du","musst","jetzt","gehen","."],"Du musst jetzt gehen.","'müssen' expresses necessity; time adverb before infinitive.","Subject + Modal + Time + Infinitive (end)"),
("A2","Modalverben",["Er","will","Arzt","werden","."],"Er will Arzt werden.","'wollen' expresses intention; 'werden' is the infinitive.","Subject + Modal + Noun + Infinitive (end)"),
("A2","Modalverben",["Sie","darf","hier","nicht","rauchen","."],"Sie darf hier nicht rauchen.","'dürfen + nicht' = prohibition; location before 'nicht'.","Subject + Modal + Location + nicht + Infinitive (end)"),
("A2","Modalverben",["Wir","sollen","leise","sein","."],"Wir sollen leise sein.","'sollen' conveys an instruction; adjective before 'sein'.","Subject + Modal + Adjective + sein (end)"),
("A2","Modalverben",["Ihr","mögt","keinen","Spinat","."],"Ihr mögt keinen Spinat.","'mögen' expresses liking or disliking; 'keinen' negates the masculine noun.","Subject + mögen + keinen + Noun"),
("A2","Modalverben",["Ich","möchte","einen","Kaffee","bitte","."],"Ich möchte einen Kaffee bitte.","'möchte' (would like) is the polite form; 'bitte' at the end softens the request.","Subject + möchte + einen + Noun + bitte"),
("A2","Modalverben",["Er","kann","kein","Deutsch","sprechen","."],"Er kann kein Deutsch sprechen.","'kein' negates the language object; infinitive at end.","Subject + Modal + kein + Object + Infinitive (end)"),
("A2","Modalverben",["Wir","müssen","früh","aufstehen","."],"Wir müssen früh aufstehen.","'müssen' + separable infinitive; the whole infinitive (including prefix) goes to end.","Subject + Modal + Adverb + Separable infinitive (end)"),
("A2","Modalverben",["Du","kannst","mir","helfen","."],"Du kannst mir helfen.","'helfen' takes dative 'mir'; infinitive at end.","Subject + Modal + Dative pronoun + Infinitive (end)"),
("A2","Modalverben",["Sie","will","nicht","in","die","Schule","gehen","."],"Sie will nicht in die Schule gehen.","'nicht' before the destination phrase; infinitive at end.","Subject + Modal + nicht + Destination + Infinitive (end)"),
("A2","Modalverben",["Ich","soll","mehr","Sport","machen","."],"Ich soll mehr Sport machen.","'sollen' for advice/instruction; 'mehr' (more) before object.","Subject + Modal + mehr + Noun + Infinitive (end)"),
("A2","Modalverben",["Er","muss","zum","Arzt","gehen","."],"Er muss zum Arzt gehen.","'zum' = zu dem (dative); destination before infinitive.","Subject + Modal + zum + Noun + Infinitive (end)"),
("A2","Modalverben",["Wir","dürfen","hier","parken","."],"Wir dürfen hier parken.","'dürfen' expresses permission; location before infinitive.","Subject + Modal + Location + Infinitive (end)"),
("A2","Modalverben",["Du","musst","die","Hausaufgaben","machen","."],"Du musst die Hausaufgaben machen.","'müssen' + direct object + infinitive at end.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Ich","kann","morgen","nicht","kommen","."],"Ich kann morgen nicht kommen.","Time adverb before 'nicht'; infinitive at very end.","Subject + Modal + Time + nicht + Infinitive (end)"),
("A2","Modalverben",["Sie","möchte","eine","Reise","nach","Italien","machen","."],"Sie möchte eine Reise nach Italien machen.","'möchte' + object + destination phrase + infinitive at end.","Subject + möchte + Object + Destination + Infinitive (end)"),
("A2","Modalverben",["Wir","wollen","ein","Haus","kaufen","."],"Wir wollen ein Haus kaufen.","'wollen' expresses desire; object before infinitive at end.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Er","soll","sofort","zurückrufen","."],"Er soll sofort zurückrufen.","'sofort' (immediately) before the separable infinitive.","Subject + Modal + Adverb + Separable infinitive (end)"),
("A2","Modalverben",["Du","darfst","das","Wörterbuch","benutzen","."],"Du darfst das Wörterbuch benutzen.","'dürfen' for permission; object before infinitive.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Kann","ich","Sie","etwas","fragen","?"],"Kann ich Sie etwas fragen?","Question: modal at position 1; formal 'Sie' as object.","Modal + Subject + Sie + etwas + Infinitive + ?"),
("A2","Modalverben",["Müsst","ihr","morgen","arbeiten","?"],"Müsst ihr morgen arbeiten?","Modal-first question: 'müsst ihr' = do you (pl.) have to.","Modal + Subject + Time + Infinitive + ?"),
("A2","Modalverben",["Er","kann","sehr","gut","kochen","."],"Er kann sehr gut kochen.","'sehr gut' adverb phrase before the infinitive.","Subject + Modal + sehr gut + Infinitive (end)"),
("A2","Modalverben",["Wir","müssen","das","Formular","ausfüllen","."],"Wir müssen das Formular ausfüllen.","Object before the separable infinitive ('ausfüllen').","Subject + Modal + Object + Separable infinitive (end)"),
("A2","Modalverben",["Sie","darf","das","Auto","benutzen","."],"Sie darf das Auto benutzen.","Permission: 'dürfen' + object + infinitive.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Ich","will","ein","Buch","schreiben","."],"Ich will ein Buch schreiben.","'wollen' + object + infinitive at end.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Du","sollst","die","Wahrheit","sagen","."],"Du sollst die Wahrheit sagen.","'sollen' for moral obligation; object before infinitive.","Subject + Modal + Object + Infinitive (end)"),
("A2","Modalverben",["Sie","kann","Klavier","spielen","."],"Sie kann Klavier spielen.","Ability with 'können'; instrument noun before infinitive.","Subject + Modal + Instrument + Infinitive (end)"),
("A2","Modalverben",["Er","muss","das","Projekt","fertig","machen","."],"Er muss das Projekt fertig machen.","'fertig machen' = to finish; 'fertig' acts as a complement before 'machen'.","Subject + Modal + Object + fertig + Infinitive (end)"),
("A2","Modalverben",["Wir","wollen","heute","Abend","ins","Kino","gehen","."],"Wir wollen heute Abend ins Kino gehen.","'ins Kino gehen' is a fixed phrase; time before destination.","Subject + Modal + Time + ins + Noun + Infinitive (end)"),
("A2","Modalverben",["Sie","muss","heute","Überstunden","machen","."],"Sie muss heute Überstunden machen.","Time adverb 'heute' before object; infinitive at end.","Subject + Modal + Time + Object + Infinitive (end)"),

# ── Perfekt (261–300) ─────────────────────
("A2","Perfekt",["Ich","habe","ein","Buch","gelesen","."],"Ich habe ein Buch gelesen.","Present perfect: auxiliary 'haben' at position 2; past participle at the end.","Subject + haben + Object + Past participle (end)"),
("A2","Perfekt",["Er","hat","Fußball","gespielt","."],"Er hat Fußball gespielt.","Regular past participle: ge- + stem + -t (gespielt).","Subject + hat + Object + Participle (ge-…-t)"),
("A2","Perfekt",["Wir","haben","Pizza","gegessen","."],"Wir haben Pizza gegessen.","Irregular participle: 'gegessen' (eaten); no article with 'Pizza'.","Subject + haben + Object + Irregular participle (end)"),
("A2","Perfekt",["Sie","ist","nach","Berlin","gefahren","."],"Sie ist nach Berlin gefahren.","Movement verbs use 'sein'; 'nach + city' for destination.","Subject + sein + Destination + Participle (end)"),
("A2","Perfekt",["Ich","bin","früh","aufgestanden","."],"Ich bin früh aufgestanden.","Separable verb perfekt: 'auf' inserts between 'ge-' and stem → 'aufgestanden'; uses 'sein'.","Subject + sein + Adverb + Separable participle (end)"),
("A2","Perfekt",["Du","hast","viel","geschlafen","."],"Du hast viel geschlafen.","Irregular participle: 'geschlafen'; 'viel' (much) before it.","Subject + hast + viel + Participle (end)"),
("A2","Perfekt",["Er","ist","gestern","gekommen","."],"Er ist gestern gekommen.","'kommen' uses 'sein'; time adverb before participle.","Subject + sein + Time + Participle (end)"),
("A2","Perfekt",["Wir","haben","das","Museum","besucht","."],"Wir haben das Museum besucht.","Inseparable verbs (be-, ver-, etc.) take no 'ge-' prefix.","Subject + haben + Object + Participle (no ge-, inseparable)"),
("A2","Perfekt",["Sie","hat","eine","E-Mail","geschrieben","."],"Sie hat eine E-Mail geschrieben.","Irregular participle: 'geschrieben'; object before participle.","Subject + hat + Object + Irregular participle (end)"),
("A2","Perfekt",["Ich","bin","zu","Fuß","gegangen","."],"Ich bin zu Fuß gegangen.","'gehen' uses 'sein'; manner phrase 'zu Fuß' before participle.","Subject + sein + zu Fuß + Participle (end)"),
("A2","Perfekt",["Er","hat","seinen","Schlüssel","verloren","."],"Er hat seinen Schlüssel verloren.","Inseparable verb 'verlieren': no 'ge-'; irregular participle 'verloren'.","Subject + hat + Object + Participle (no ge-)"),
("A2","Perfekt",["Wir","haben","die","ganze","Nacht","getanzt","."],"Wir haben die ganze Nacht getanzt.","Duration phrase 'die ganze Nacht' between auxiliary and participle.","Subject + haben + Duration + Participle (end)"),
("A2","Perfekt",["Sie","ist","um","Mitternacht","nach","Hause","gefahren","."],"Sie ist um Mitternacht nach Hause gefahren.","Movement + 'sein'; time first, then destination, participle at end.","Subject + sein + Time + Destination + Participle (end)"),
("A2","Perfekt",["Ich","habe","meinen","Vater","angerufen","."],"Ich habe meinen Vater angerufen.","Separable 'anrufen': participle = 'an' + 'ge' + 'rufen' = 'angerufen'.","Subject + haben + Object + Separable participle (end)"),
("A2","Perfekt",["Du","hast","einen","Fehler","gemacht","."],"Du hast einen Fehler gemacht.","Regular participle 'gemacht'; masculine accusative object.","Subject + hast + Object + Participle (end)"),
("A2","Perfekt",["Er","ist","nach","Hause","gegangen","."],"Er ist nach Hause gegangen.","'gehen' uses 'sein'; destination 'nach Hause' before participle.","Subject + sein + Destination + Participle (end)"),
("A2","Perfekt",["Wir","haben","lange","gewartet","."],"Wir haben lange gewartet.","Duration adverb 'lange' before the participle.","Subject + haben + lange + Participle (end)"),
("A2","Perfekt",["Sie","hat","das","Lied","gesungen","."],"Sie hat das Lied gesungen.","Irregular participle 'gesungen'; object before participle.","Subject + hat + Object + Irregular participle (end)"),
("A2","Perfekt",["Ich","habe","Deutsch","gelernt","."],"Ich habe Deutsch gelernt.","Regular participle 'gelernt'; no article for language names.","Subject + haben + Language + Participle (end)"),
("A2","Perfekt",["Er","hat","das","Auto","repariert","."],"Er hat das Auto repariert.","'-ieren' verbs: no 'ge-' prefix (repariert, not *gerepariert).","Subject + hat + Object + Participle (-iert, no ge-)"),
("A2","Perfekt",["Wir","sind","um","sechs","Uhr","aufgestanden","."],"Wir sind um sechs Uhr aufgestanden.","'aufstehen' (separable) + 'sein'; time before separable participle.","Subject + sein + Time + Separable participle (end)"),
("A2","Perfekt",["Sie","haben","den","Film","gesehen","."],"Sie haben den Film gesehen.","Irregular participle 'gesehen'; masculine accusative object.","Subject + haben + den + Noun + Participle (end)"),
("A2","Perfekt",["Ich","habe","meinen","Geburtstag","gefeiert","."],"Ich habe meinen Geburtstag gefeiert.","Regular participle 'gefeiert'; possessive accusative object.","Subject + haben + Object + Participle (end)"),
("A2","Perfekt",["Du","bist","mit","dem","Zug","gefahren","."],"Du bist mit dem Zug gefahren.","'fahren' uses 'sein'; means of transport with 'mit + dative'.","Subject + sein + mit + dem + Noun + Participle (end)"),
("A2","Perfekt",["Er","hat","seine","Hausaufgaben","vergessen","."],"Er hat seine Hausaufgaben vergessen.","Inseparable 'vergessen': no 'ge-'; irregular form stays 'vergessen'.","Subject + hat + Object + Participle (no ge-, inseparable)"),
("A2","Perfekt",["Wir","haben","im","Restaurant","gegessen","."],"Wir haben im Restaurant gegessen.","Location phrase before participle; 'gegessen' is irregular.","Subject + haben + Location + Participle (end)"),
("A2","Perfekt",["Sie","ist","nach","Hause","geflogen","."],"Sie ist nach Hause geflogen.","'fliegen' uses 'sein'; destination before participle.","Subject + sein + Destination + Participle (end)"),
("A2","Perfekt",["Ich","habe","ein","neues","Handy","gekauft","."],"Ich habe ein neues Handy gekauft.","Regular participle 'gekauft'; adjective inside the object phrase.","Subject + haben + ein + Adj + Object + Participle (end)"),
("A2","Perfekt",["Er","hat","die","Zeitung","gelesen","."],"Er hat die Zeitung gelesen.","Irregular participle 'gelesen'; definite accusative object.","Subject + hat + die + Noun + Participle (end)"),
("A2","Perfekt",["Du","hast","gut","gespielt","."],"Du hast gut gespielt.","Regular participle 'gespielt'; manner adverb 'gut' before it.","Subject + hast + gut + Participle (end)"),
("A2","Perfekt",["Sie","hat","einen","Deutschkurs","belegt","."],"Sie hat einen Deutschkurs belegt.","Inseparable 'belegen': no 'ge-'; regular ending '-t'.","Subject + hat + Object + Participle (no ge-)"),

# ── TeKaMoLo / Dativ / Präpositionen (301–350) ───────────────
("A2","TeKaMoLo",["Er","fährt","jeden","Tag","mit","dem","Fahrrad","zur","Arbeit","."],"Er fährt jeden Tag mit dem Fahrrad zur Arbeit.","TeKaMoLo order: Time (jeden Tag) → Manner (mit dem Fahrrad) → Place (zur Arbeit).","Subject + Verb + Time + Manner + Place"),
("A2","TeKaMoLo",["Sie","geht","abends","allein","ins","Fitnessstudio","."],"Sie geht abends allein ins Fitnessstudio.","Time (abends) → Manner (allein) → Place (ins Fitnessstudio).","Subject + Verb + Time + Manner + Place"),
("A2","TeKaMoLo",["Ich","fahre","morgen","mit","dem","Zug","nach","München","."],"Ich fahre morgen mit dem Zug nach München.","Time (morgen) → Manner (mit dem Zug) → Place (nach München).","Subject + Verb + Time + Manner + Place"),
("A2","TeKaMoLo",["Wir","essen","heute","Abend","zusammen","in","einem","Restaurant","."],"Wir essen heute Abend zusammen in einem Restaurant.","Time (heute Abend) → Manner (zusammen) → Place (in einem Restaurant).","Subject + Verb + Time + Manner + Place"),
("A2","TeKaMoLo",["Er","hat","gestern","schnell","seinen","Kaffee","getrunken","."],"Er hat gestern schnell seinen Kaffee getrunken.","Perfekt + TeKaMoLo: Time (gestern) → Manner (schnell) → Object → Participle.","Subject + haben + Time + Manner + Object + Participle (end)"),
("A2","Dativ",["Ich","helfe","meinem","Vater","im","Garten","."],"Ich helfe meinem Vater im Garten.","'helfen' always takes dative; 'meinem' is dative masculine.","Subject + helfen + Dative object + Location"),
("A2","Dativ",["Er","gibt","seiner","Schwester","ein","Geschenk","."],"Er gibt seiner Schwester ein Geschenk.","'geben' takes two objects: dative (seiner Schwester) then accusative (ein Geschenk).","Subject + geben + Dative + Accusative"),
("A2","Dativ",["Ich","danke","dir","für","deine","Hilfe","."],"Ich danke dir für deine Hilfe.","'danken' takes dative ('dir'); reason given with 'für + accusative'.","Subject + danken + Dative + für + Accusative"),
("A2","Dativ",["Sie","gehört","meiner","Freundin","."],"Sie gehört meiner Freundin.","'gehören' takes dative; feminine dative: 'meiner'.","Subject + gehören + Dative (fem.)"),
("A2","Dativ",["Wir","erzählen","unseren","Kindern","eine","Geschichte","."],"Wir erzählen unseren Kindern eine Geschichte.","'erzählen': dative ('unseren Kindern') then accusative ('eine Geschichte').","Subject + erzählen + Dative + Accusative"),
("A2","Dativ",["Er","schreibt","seinem","Bruder","eine","Nachricht","."],"Er schreibt seinem Bruder eine Nachricht.","'schreiben': dative recipient ('seinem Bruder') before accusative object.","Subject + schreiben + Dative + Accusative"),
("A2","Dativ",["Das","Buch","gefällt","mir","sehr","."],"Das Buch gefällt mir sehr.","'gefallen' takes dative; the thing liked is the grammatical subject.","Subject (thing) + gefallen + Dative + sehr"),
("A2","Dativ",["Ich","empfehle","Ihnen","dieses","Restaurant","."],"Ich empfehle Ihnen dieses Restaurant.","'empfehlen': dative 'Ihnen' (formal you) then accusative object.","Subject + empfehlen + Ihnen (dat.) + Accusative"),
("A2","Dativ",["Sie","hilft","ihrem","Nachbarn","oft","."],"Sie hilft ihrem Nachbarn oft.","'helfen' + dative; 'ihrem Nachbarn' = her neighbour (dative masculine).","Subject + helfen + Dative + Frequency"),
("A2","Dativ",["Das","Auto","gehört","unserem","Vater","."],"Das Auto gehört unserem Vater.","'gehören' + dative; 'unserem Vater' = dative masculine.","Subject + gehören + Dative (masc.)"),
("A2","Dativ",["Er","schenkt","seiner","Freundin","Blumen","."],"Er schenkt seiner Freundin Blumen.","'schenken': dative recipient then accusative object (no article with plural 'Blumen').","Subject + schenken + Dative + Accusative (pl.)"),
("A2","Dativ",["Ich","zeige","dir","den","Weg","."],"Ich zeige dir den Weg.","'zeigen': dative pronoun 'dir' before the accusative object.","Subject + zeigen + Dative pronoun + Accusative"),
("A2","Dativ",["Das","Essen","schmeckt","uns","sehr","gut","."],"Das Essen schmeckt uns sehr gut.","'schmecken' takes dative 'uns'; 'sehr gut' follows.","Subject + schmecken + Dative + sehr gut"),
("A2","Präpositionen",["Er","kommt","aus","einer","kleinen","Stadt","."],"Er kommt aus einer kleinen Stadt.","'aus + dative' for origin; 'einer' is dative feminine.","Subject + Verb + aus + einer + Adj + Noun"),
("A2","Präpositionen",["Sie","fährt","mit","ihren","Freunden","in","den","Urlaub","."],"Sie fährt mit ihren Freunden in den Urlaub.","'mit + dative' for company; 'in den Urlaub' (accusative, direction).","Subject + Verb + mit + Dative + in + Accusative"),
("A2","Präpositionen",["Das","Buch","liegt","auf","dem","Tisch","."],"Das Buch liegt auf dem Tisch.","'liegen auf + dative' = static position (where something rests).","Subject + liegen + auf + dem + Noun (dative, static)"),
("A2","Präpositionen",["Er","stellt","das","Buch","auf","den","Tisch","."],"Er stellt das Buch auf den Tisch.","'stellen auf + accusative' = movement onto a surface (direction).","Subject + stellen + Object + auf + den + Noun (acc., movement)"),
("A2","Präpositionen",["Ich","warte","auf","den","Bus","."],"Ich warte auf den Bus.","'warten auf + accusative' is a fixed prepositional verb.","Subject + warten + auf + Accusative"),
("A2","Präpositionen",["Er","interessiert","sich","für","Musik","."],"Er interessiert sich für Musik.","'sich interessieren für + accusative' is a reflexive prepositional verb.","Subject + sich interessieren + für + Accusative"),
("A2","Präpositionen",["Sie","freut","sich","auf","die","Ferien","."],"Sie freut sich auf die Ferien.","'sich freuen auf + accusative' = looking forward to something future.","Subject + sich freuen + auf + Accusative"),
("A2","Präpositionen",["Das","Café","ist","neben","dem","Bahnhof","."],"Das Café ist neben dem Bahnhof.","'neben + dative' for static location (next to).","Subject + sein + neben + dem + Noun"),
("A2","Präpositionen",["Er","hängt","das","Bild","an","die","Wand","."],"Er hängt das Bild an die Wand.","'hängen an + accusative' = movement (putting something on the wall).","Subject + hängen + Object + an + die + Noun (acc.)"),
("A2","Präpositionen",["Wir","treffen","uns","vor","dem","Kino","."],"Wir treffen uns vor dem Kino.","'vor + dative' for a static meeting point in front of something.","Subject + treffen + uns + vor + dem + Noun"),
("A2","Präpositionen",["Sie","denkt","oft","an","ihre","Heimat","."],"Sie denkt oft an ihre Heimat.","'denken an + accusative' is a fixed prepositional verb.","Subject + denken + oft + an + Accusative"),
("A2","Präpositionen",["Wir","sprechen","über","das","Wochenende","."],"Wir sprechen über das Wochenende.","'sprechen über + accusative' = to talk about something.","Subject + sprechen + über + Accusative"),
("A2","Präpositionen",["Er","ärgert","sich","über","den","Lärm","."],"Er ärgert sich über den Lärm.","'sich ärgern über + accusative' = to be annoyed about something.","Subject + sich ärgern + über + Accusative"),

# ── Komparativ / Imperativ (331–350) ──────
("A2","Komparativ",["Er","ist","größer","als","sein","Bruder","."],"Er ist größer als sein Bruder.","Comparative: adjective + -er + 'als' to compare two things.","Subject + sein + Adjective-er + als + Noun"),
("A2","Komparativ",["Das","neue","Handy","ist","teurer","als","das","alte","."],"Das neue Handy ist teurer als das alte.","'teurer' = teuer + -er (with umlaut); 'als' links the two items.","Subject + sein + Comparative + als + Object"),
("A2","Komparativ",["Sie","spricht","besser","Englisch","als","ich","."],"Sie spricht besser Englisch als ich.","Irregular comparative: 'gut → besser'; pronoun after 'als' stays nominative.","Subject + Verb + besser + Object + als + Pronoun"),
("A2","Komparativ",["Dieses","Restaurant","ist","so","gut","wie","das","andere","."],"Dieses Restaurant ist so gut wie das andere.","Equality: 'so + adjective + wie' (as good as).","Subject + sein + so + Adjective + wie + Object"),
("A2","Komparativ",["Der","Zug","ist","schneller","als","der","Bus","."],"Der Zug ist schneller als der Bus.","Standard comparative pattern: -er + als.","Subject + sein + Comparative + als + Subject"),
("A2","Komparativ",["Sie","lernt","fleißiger","als","ihr","Bruder","."],"Sie lernt fleißiger als ihr Bruder.","Adverb comparative: 'fleißig → fleißiger'; 'als' for comparison.","Subject + Verb + Adverb-er + als + Noun"),
("A2","Komparativ",["Heute","ist","es","wärmer","als","gestern","."],"Heute ist es wärmer als gestern.","Weather comparative; 'es' is the dummy weather subject.","Time + sein + es + Comparative + als + Time"),
("A2","Komparativ",["Meine","Wohnung","ist","kleiner","als","seine","."],"Meine Wohnung ist kleiner als seine.","Possessive pronoun 'seine' (his, referring to Wohnung) after 'als'.","Subject + sein + Comparative + als + Pronoun"),
("A2","Komparativ",["Er","arbeitet","mehr","als","alle","anderen","."],"Er arbeitet mehr als alle anderen.","Irregular comparative of 'viel': 'mehr' (more).","Subject + Verb + mehr + als + Pronoun/Noun"),
("A2","Komparativ",["Je","mehr","ich","lerne",",","desto","besser","werde","ich","."],"Je mehr ich lerne, desto besser werde ich.","'Je mehr…desto besser' = the more…the better; verb at end of first clause.","Je + mehr + Subject + Verb (end), desto + Adj + Verb + Subject"),
("A2","Imperativ",["Mach","bitte","die","Tür","zu","!"],"Mach bitte die Tür zu!","Imperative of separable verb: stem first, object in middle, prefix 'zu' at end.","Verb stem + bitte + Object + Prefix (end) + !"),
("A2","Imperativ",["Kommen","Sie","bitte","herein","!"],"Kommen Sie bitte herein!","Formal imperative: full verb + 'Sie' + 'bitte'; prefix 'herein' at end.","Verb + Sie + bitte + Prefix (end) + !"),
("A2","Imperativ",["Schreib","deinen","Namen","auf","das","Formular","!"],"Schreib deinen Namen auf das Formular!","Informal imperative (du-form): verb stem, then object, then 'auf + accusative'.","Verb stem + Object + auf + Accusative + !"),
("A2","Imperativ",["Seid","bitte","ruhig","!"],"Seid bitte ruhig!","Imperative ihr-form of 'sein': 'seid'; adjective after 'bitte'.","seid + bitte + Adjective + !"),
("A2","Imperativ",["Gehen","wir","zusammen","!"],"Gehen wir zusammen!","'Gehen wir' = let's go; verb first, 'wir' second.","Verb + wir + Adverb + !"),
("A2","Imperativ",["Hilf","mir","bitte","!"],"Hilf mir bitte!","Irregular imperative of 'helfen': 'hilf' (vowel change e→i); dative 'mir'.","hilf (irregular) + Dative + bitte + !"),
("A2","Imperativ",["Lest","den","Text","noch","einmal","!"],"Lest den Text noch einmal!","Ihr-form imperative: 'lest'; 'noch einmal' (once more) after object.","lest + Object + noch einmal + !"),
("A2","Imperativ",["Sprich","bitte","langsamer","!"],"Sprich bitte langsamer!","Irregular imperative: 'sprechen → sprich' (e→i vowel change); comparative adverb.","sprich (irregular) + bitte + Comparative adverb + !"),
("A2","Imperativ",["Nehmt","eure","Bücher","heraus","!"],"Nehmt eure Bücher heraus!","Ihr-form of separable 'herausnehmen': object before prefix.","nehmt + Possessive + Object + Prefix (end) + !"),
("A2","Modalverben",["Wir","können","das","Problem","lösen","."],"Wir können das Problem lösen.","'können' (can/be able to); object before infinitive at end.","Subject + können + Object + Infinitive (end)"),
("A2","Modalverben",["Er","darf","das","Zimmer","nicht","verlassen","."],"Er darf das Zimmer nicht verlassen.","'nicht' before the infinitive negates the action (prohibition).","Subject + Modal + Object + nicht + Infinitive (end)"),
("A2","Perfekt",["Ich","habe","meinen","Pass","vergessen","."],"Ich habe meinen Pass vergessen.","'vergessen' stays the same as its own participle (irregular, inseparable).","Subject + haben + Object + Participle (end)"),
("A2","Perfekt",["Er","ist","nach","Hause","gelaufen","."],"Er ist nach Hause gelaufen.","'laufen' uses 'sein' (movement verb); destination before participle.","Subject + sein + Destination + Participle (end)"),
("A2","Perfekt",["Wir","haben","das","Konzert","genossen","."],"Wir haben das Konzert genossen.","'genießen → genossen' irregular; inseparable: no 'ge-' prefix.","Subject + haben + Object + Participle (end)"),
("A2","Perfekt",["Du","hast","die","Aufgabe","erledigt","."],"Du hast die Aufgabe erledigt.","'erledigen → erledigt' regular; inseparable: no 'ge-'.","Subject + hast + Object + Participle (end)"),

